import java.nio.file._
def fileUpload(filename: String) {
  Source.fromFile("uploads/" + filename).mkString
}

def upload(fileName: String, data: InputStream)(implicit session: Session) = Action { implicit request =>
  Files.copy(request.body.data.stream, Paths.get(s"uploads/$fileName"), StandardCopyOption.REPLACE_EXISTING)
    Redirect(controllers.routes.Files.fileUpload(fileName))
}